"use client"

import { useEffect, useState } from "react"
import { useParams } from "next/navigation"
import { AdminLayout } from "@/components/admin-layout"
import { 
  ArrowLeft, 
  CheckCircle2, 
  Circle, 
  AlertCircle, 
  MapPin, 
  Loader2,
  Calendar,
  FileText,
  CheckSquare,
  DollarSign,
  TrendingUp,
  Lock
} from "lucide-react"
import Link from "next/link"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"

interface ChecklistItem {
  _id: string
  label: string
  completed: boolean
  notes?: string
  dueDate?: string
}

interface ExecutionData {
  property?: {
    address: string
    city?: string
    state?: string
    zipCode?: string
  }
  phase1?: {
    arv?: {
      baseArv?: number
      finalArv?: number
      adjustmentSteps?: any[]
    }
    costs?: {
      purchasePrice?: number
      closingCosts?: number
      holdingCosts?: number
      rehabCost?: number
      totalCosts?: number
    }
  }
  workspace?: {
    _id: string
    stage: string
  }
  checklist?: ChecklistItem[]
}

const stageConfig = {
  DUE_DILIGENCE: {
    label: "Due Diligence",
    color: "bg-blue-50 dark:bg-blue-900/30",
    textColor: "text-blue-700 dark:text-blue-300",
    borderColor: "border-blue-200 dark:border-blue-700",
  },
  BIDDING: {
    label: "Bidding",
    color: "bg-purple-50 dark:bg-purple-900/30",
    textColor: "text-purple-700 dark:text-purple-300",
    borderColor: "border-purple-200 dark:border-purple-700",
  },
  REHAB: {
    label: "Rehab",
    color: "bg-orange-50 dark:bg-orange-900/30",
    textColor: "text-orange-700 dark:text-orange-300",
    borderColor: "border-orange-200 dark:border-orange-700",
  },
  CLOSING: {
    label: "Closing",
    color: "bg-emerald-50 dark:bg-emerald-900/30",
    textColor: "text-emerald-700 dark:text-emerald-300",
    borderColor: "border-emerald-200 dark:border-emerald-700",
  },
}

const stageOrder = ["DUE_DILIGENCE", "BIDDING", "REHAB", "CLOSING"]

export default function ExecutionDetail() {
  const params = useParams()
  const propertyId = params?.propertyId as string | null
const [costs, setCosts] = useState<any[]>([])
const [costLoading, setCostLoading] = useState(false)

  const [data, setData] = useState<ExecutionData | null>(null)
  const [isLoading, setIsLoading] = useState(true)
  const [isSaving, setIsSaving] = useState(false)
  const [activeTab, setActiveTab] = useState<"checklist" | "snapshot" | "costs">("checklist")
  const [error, setError] = useState<string | null>(null)
  const [isReady, setIsReady] = useState(false)
  const [checklistItems, setChecklistItems] = useState<ChecklistItem[]>([])

  // Load checklist from localStorage

  useEffect(() => {
    setIsReady(true)
  }, [])
useEffect(() => {
  if (!data?.workspace?._id) return

  const fetchCosts = async () => {
    setCostLoading(true)
    const res = await fetch(
      `/api/execution/costs/${data?.workspace?._id}`
    )
    const result = await res.json()
    setCosts(result)
    setCostLoading(false)
  }

  fetchCosts()
}, [data?.workspace?._id])
const totalPlanned = costs.reduce(
  (sum, c) => sum + c.plannedAmount,
  0
)

const totalActual = costs.reduce(
  (sum, c) => sum + c.actualAmount,
  0
)

const totalVariance = totalActual - totalPlanned

const variancePercent =
  totalPlanned > 0
    ? (totalVariance / totalPlanned) * 100
    : 0

  useEffect(() => {
    if (!isReady || !propertyId) return

    const fetchData = async () => {
      try {
        setIsLoading(true)
        const res = await fetch(`/api/execution/properties/${propertyId}`, {
          cache: "no-store",
        })
        
        if (!res.ok) {
          const errorData = await res.json()
          throw new Error(errorData.message || `Error ${res.status}: Failed to fetch property details`)
        }
        
        const result = await res.json()
        setData(result)
        
        // Initialize checklist from API if localStorage is empty
        if (result.checklist && checklistItems.length === 0) {
          setChecklistItems(result.checklist)
        }
      } catch (err) {
        setError(err instanceof Error ? err.message : "An error occurred")
      } finally {
        setIsLoading(false)
      }
    }

    fetchData()
  }, [isReady, propertyId])
const updateActual = async (id: string, value: number) => {
  const res = await fetch(
    `/api/execution/costs/item/${id}`,
    {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        actualAmount: value,
      }),
    }
  )

  if (!res.ok) return

  const updated = await res.json()

  setCosts(prev =>
    prev.map(c =>
      c._id === id ? updated : c
    )
  )
}

  const handleStageChange = async (newStage: string) => {
    if (!data?.workspace) return

    try {
      setIsSaving(true)
      const res = await fetch("/api/execution/stage", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          workspaceId: data.workspace._id,
          stage: newStage,
        }),
      })
      if (!res.ok) throw new Error("Failed to update stage")
      setData({ ...data, workspace: { ...data.workspace, stage: newStage } })
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to update stage")
    } finally {
      setIsSaving(false)
    }
  }
const addCost = async () => {
  const res = await fetch("/api/execution/costs", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      executionWorkspaceId: data?.workspace?._id,
      category: "New Category",
      plannedAmount: 0,
    }),
  })

  const newItem = await res.json()
  setCosts(prev => [...prev, newItem])
}

const handleChecklistChange = async (itemId: string, completed: boolean) => {
  try {
    const res = await fetch("/api/execution/checklist", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        itemId,
        completed,
      }),
    })

    if (!res.ok) throw new Error("Failed to update checklist")

    // Update UI after DB success
    setChecklistItems(prev =>
      prev.map(item =>
        item._id === itemId ? { ...item, completed } : item
      )
    )

  } catch (err) {
    setError("Failed to update checklist")
  }
}


  if (!isReady || !propertyId || isLoading) {
    return (
      <AdminLayout>
        <div className="p-8 max-w-7xl mx-auto">
          <div className="flex items-center justify-center py-24">
            <div className="text-center">
              <Loader2 className="w-12 h-12 text-blue-600 dark:text-blue-400 mx-auto mb-4 animate-spin" />
              <p className="text-gray-600 dark:text-gray-400">Loading property details...</p>
            </div>
          </div>
        </div>
      </AdminLayout>
    )
  }

  if (!data) {
    return (
      <AdminLayout>
        <div className="p-8 max-w-7xl mx-auto">
          <div className="bg-yellow-50 dark:bg-yellow-950/50 border border-yellow-200 dark:border-yellow-800 rounded-lg p-6 flex items-center gap-3">
            <AlertCircle className="w-6 h-6 text-yellow-600 dark:text-yellow-400" />
            <p className="text-yellow-700 dark:text-yellow-300">No data found for this property</p>
          </div>
        </div>
      </AdminLayout>
    )
  }

  const currentStageIndex = stageOrder.indexOf(data.workspace?.stage || "DUE_DILIGENCE")
  const currentStageConfig = stageConfig[data.workspace?.stage as keyof typeof stageConfig]
  const completedChecklistCount = checklistItems.filter(item => item.completed).length
  const totalChecklistCount = checklistItems.length
  const checklistProgress = totalChecklistCount > 0 ? (completedChecklistCount / totalChecklistCount) * 100 : 0

  // Extract costs from Phase 1 data
  const purchasePrice = data.phase1?.costs?.purchasePrice || 0
  const rehabCost = data.phase1?.costs?.rehabCost || 0
  const holdingCosts = data.phase1?.costs?.holdingCosts || 0
  const closingCosts = data.phase1?.costs?.closingCosts || 0
  const totalCosts = data.phase1?.costs?.totalCosts || 0
  const arv = data.phase1?.arv?.finalArv || data.phase1?.arv?.baseArv || 0

  return (
    <AdminLayout>
      <div className="min-h-screen bg-gray-50 dark:bg-gray-900">
        <div className="p-6 lg:p-8 max-w-7xl mx-auto">
          {/* Error Alert */}
          {error && (
            <div className="mb-6 bg-red-50 dark:bg-red-950/50 border border-red-200 dark:border-red-800 rounded-lg p-4 flex items-center gap-3">
              <AlertCircle className="w-5 h-5 text-red-600 dark:text-red-400 flex-shrink-0" />
              <p className="text-red-700 dark:text-red-300 text-sm">{error}</p>
            </div>
          )}

          {/* Back Button */}
          <Link href="/execution">
            <button className="flex items-center gap-2 text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 font-medium mb-6 transition-colors">
              <ArrowLeft className="w-4 h-4" />
              Back to Executions
            </button>
          </Link>

          {/* Header */}
          <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6 mb-6">
            <div className="flex items-start justify-between mb-4">
              <div>
                <h1 className="text-3xl font-bold text-gray-900 dark:text-gray-50 mb-2">
                  {data.property?.address}
                </h1>
                <div className="flex items-center gap-2 text-gray-600 dark:text-gray-400">
                  <MapPin className="w-4 h-4" />
                  <span className="text-sm">
                    {[data.property?.city, data.property?.state, data.property?.zipCode]
                      .filter(Boolean)
                      .join(", ")}
                  </span>
                </div>
              </div>
              <div className={`px-4 py-2 rounded-lg font-semibold border ${currentStageConfig?.textColor} ${currentStageConfig?.color} ${currentStageConfig?.borderColor}`}>
                {currentStageConfig?.label}
              </div>
            </div>

            {/* Stage Progress */}
            <div className="mt-6">
              <div className="flex items-center justify-between mb-3">
                <p className="text-sm font-semibold text-gray-700 dark:text-gray-300">Execution Progress</p>
                <p className="text-sm text-gray-600 dark:text-gray-400">{currentStageIndex + 1} of {stageOrder.length}</p>
              </div>
              <div className="w-full h-2 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
                <div
                  className="h-full bg-blue-600 dark:bg-blue-500 transition-all duration-300"
                  style={{ width: `${((currentStageIndex + 1) / stageOrder.length) * 100}%` }}
                />
              </div>
              <div className="grid grid-cols-4 gap-2 mt-4">
                {stageOrder.map((stage, index) => (
                  <div key={stage} className="flex flex-col items-center gap-2">
                    <div
                      className={`w-10 h-10 rounded-full flex items-center justify-center font-semibold text-sm transition-all ${
                        index <= currentStageIndex
                          ? "bg-blue-600 text-white dark:bg-blue-500"
                          : "bg-gray-200 dark:bg-gray-700 text-gray-600 dark:text-gray-400"
                      }`}
                    >
                      {index < currentStageIndex ? (
                        <CheckCircle2 className="w-5 h-5" />
                      ) : (
                        <span>{index + 1}</span>
                      )}
                    </div>
                    <span className="text-xs font-medium text-gray-700 dark:text-gray-300 text-center">
                      {stageConfig[stage as keyof typeof stageConfig].label}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Quick Stats */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
            {/* Stage Selector */}
            <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6">
              <div className="flex items-center gap-2 mb-4">
                <Calendar className="w-5 h-5 text-blue-600 dark:text-blue-400" />
                <h3 className="font-semibold text-gray-900 dark:text-gray-50">Update Stage</h3>
              </div>
              <div className="space-y-2">
                {stageOrder.map(stage => (
                  <button
                    key={stage}
                    onClick={() => handleStageChange(stage)}
                    disabled={isSaving}
                    className={`w-full px-4 py-2.5 rounded-lg font-medium text-sm transition-all flex items-center justify-between ${
                      data.workspace?.stage === stage
                        ? "bg-blue-600 text-white dark:bg-blue-600"
                        : "bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600"
                    }`}
                  >
                    <span>{stageConfig[stage as keyof typeof stageConfig].label}</span>
                    {data.workspace?.stage === stage && <CheckCircle2 className="w-4 h-4" />}
                  </button>
                ))}
              </div>
              {isSaving && (
                <div className="mt-3 flex items-center gap-2 text-sm text-blue-600 dark:text-blue-400">
                  <Loader2 className="w-4 h-4 animate-spin" />
                  Saving...
                </div>
              )}
            </div>

            {/* Checklist Progress */}
            <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                  <CheckSquare className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
                  <h3 className="font-semibold text-gray-900 dark:text-gray-50">Checklist</h3>
                </div>
                <span className="text-sm font-semibold text-gray-700 dark:text-gray-300">
                  {completedChecklistCount}/{totalChecklistCount}
                </span>
              </div>
              <div className="w-full h-3 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden mb-3">
                <div
                  className="h-full bg-emerald-600 dark:bg-emerald-500 transition-all duration-300"
                  style={{ width: `${checklistProgress}%` }}
                />
              </div>
              <p className="text-sm text-gray-600 dark:text-gray-400">
                {checklistProgress.toFixed(0)}% complete
              </p>
            </div>

            {/* Investment Summary */}
            <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6">
              <div className="flex items-center gap-2 mb-4">
                <DollarSign className="w-5 h-5 text-blue-600 dark:text-blue-400" />
                <h3 className="font-semibold text-gray-900 dark:text-gray-50">Investment</h3>
              </div>
              <div className="text-2xl font-bold text-gray-900 dark:text-gray-50 mb-1">
                ${totalCosts.toLocaleString()}
              </div>
              <p className="text-sm text-gray-600 dark:text-gray-400">Total Costs</p>
            </div>
          </div>

          {/* Tabs */}
          <div className="mb-6 bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700">
            <div className="flex border-b border-gray-200 dark:border-gray-700 px-6">
              <button
                onClick={() => setActiveTab("checklist")}
                className={`px-4 py-3 font-medium text-sm border-b-2 transition-all ${
                  activeTab === "checklist"
                    ? "text-blue-600 dark:text-blue-400 border-blue-600 dark:border-blue-400"
                    : "text-gray-600 dark:text-gray-400 border-transparent hover:text-gray-900 dark:hover:text-gray-200"
                }`}
              >
                <div className="flex items-center gap-2">
                  <CheckSquare className="w-4 h-4" />
                  Checklist
                </div>
              </button>
              <button
                onClick={() => setActiveTab("costs")}
                className={`px-4 py-3 font-medium text-sm border-b-2 transition-all ${
                  activeTab === "costs"
                    ? "text-blue-600 dark:text-blue-400 border-blue-600 dark:border-blue-400"
                    : "text-gray-600 dark:text-gray-400 border-transparent hover:text-gray-900 dark:hover:text-gray-200"
                }`}
              >
                <div className="flex items-center gap-2">
                  <TrendingUp className="w-4 h-4" />
                  Cost Summary
                </div>
              </button>
              <button
                onClick={() => setActiveTab("snapshot")}
                className={`px-4 py-3 font-medium text-sm border-b-2 transition-all ${
                  activeTab === "snapshot"
                    ? "text-blue-600 dark:text-blue-400 border-blue-600 dark:border-blue-400"
                    : "text-gray-600 dark:text-gray-400 border-transparent hover:text-gray-900 dark:hover:text-gray-200"
                }`}
              >
                <div className="flex items-center gap-2">
                  <FileText className="w-4 h-4" />
                  Phase 1 Data
                </div>
              </button>
            </div>

            {/* Tab Content */}
            <div className="p-6">
              {activeTab === "checklist" && (
                <>
                  {checklistItems.length > 0 ? (
                    <div className="space-y-3">
                      {checklistItems.map((item) => (
                        <div
                          key={item._id}
                          className="p-4 bg-gray-50 dark:bg-gray-700/50 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
                        >
                          <div className="flex items-start gap-4">
                            <button
                              onClick={() => handleChecklistChange(item._id, !item.completed)}
                              className="mt-0.5 flex-shrink-0 focus:outline-none transition-transform hover:scale-110"
                            >
                              {item.completed ? (
                                <CheckCircle2 className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
                              ) : (
                                <Circle className="w-5 h-5 text-gray-400 dark:text-gray-500" />
                              )}
                            </button>

                            <div className="flex-1 min-w-0">
                              <label
                                onClick={() => handleChecklistChange(item._id, !item.completed)}
                                className={`block cursor-pointer font-medium text-sm transition-colors ${
                                  item.completed
                                    ? "text-gray-400 dark:text-gray-500 line-through"
                                    : "text-gray-900 dark:text-gray-50"
                                }`}
                              >
                                {item.label}
                              </label>
                              {item.notes && (
                                <p className="text-xs text-gray-600 dark:text-gray-400 mt-1">
                                  {item.notes}
                                </p>
                              )}
                              {item.dueDate && (
                                <p className="text-xs text-gray-500 dark:text-gray-500 mt-2 flex items-center gap-1">
                                  <Calendar className="w-3 h-3" />
                                  Due: {new Date(item.dueDate).toLocaleDateString()}
                                </p>
                              )}
                            </div>

                            <div className="flex-shrink-0">
                              <span
                                className={`inline-block px-2.5 py-1 rounded-full text-xs font-medium ${
                                  item.completed
                                    ? "bg-emerald-100 dark:bg-emerald-900/50 text-emerald-700 dark:text-emerald-300"
                                    : "bg-gray-200 dark:bg-gray-600 text-gray-700 dark:text-gray-300"
                                }`}
                              >
                                {item.completed ? "Done" : "Pending"}
                              </span>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="p-12 text-center">
                      <CheckSquare className="w-12 h-12 text-gray-300 dark:text-gray-600 mx-auto mb-4" />
                      <p className="text-gray-600 dark:text-gray-400">No checklist items available</p>
                    </div>
                  )}
                </>
              )}

              {activeTab === "costs" && (
                <div className="space-y-6">
                  {/* Cost Tracking Section */}
                  <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6">
                    <div className="flex items-center justify-between mb-6">
                      <div className="flex items-center gap-2">
                        <DollarSign className="w-5 h-5 text-blue-600 dark:text-blue-400" />
                        <h3 className="text-lg font-semibold text-gray-900 dark:text-gray-50">Cost Tracking</h3>
                      </div>
                      <button
                        onClick={addCost}
                        disabled={costLoading}
                        className="px-4 py-2 bg-blue-600 hover:bg-blue-700 dark:bg-blue-600 dark:hover:bg-blue-700 text-white rounded-lg font-medium text-sm transition-colors disabled:opacity-50"
                      >
                        + Add Cost Category
                      </button>
                    </div>

                    {costLoading ? (
                      <div className="flex items-center justify-center py-8">
                        <Loader2 className="w-5 h-5 text-blue-600 dark:text-blue-400 animate-spin" />
                      </div>
                    ) : costs.length > 0 ? (
                      <>
                        {/* Table */}
                        <div className="overflow-x-auto">
                          <table className="w-full text-sm">
                            <thead>
                              <tr className="border-b border-gray-200 dark:border-gray-700">
                                <th className="text-left px-4 py-3 font-semibold text-gray-700 dark:text-gray-300">Category</th>
                                <th className="text-right px-4 py-3 font-semibold text-gray-700 dark:text-gray-300">Planned</th>
                                <th className="text-right px-4 py-3 font-semibold text-gray-700 dark:text-gray-300">Actual</th>
                                <th className="text-right px-4 py-3 font-semibold text-gray-700 dark:text-gray-300">Variance</th>
                              </tr>
                            </thead>
                            <tbody>
                              {costs.map((cost, index) => {
                                const variance = cost.actualAmount - cost.plannedAmount
                                const variancePercent = cost.plannedAmount > 0 
                                  ? (variance / cost.plannedAmount) * 100 
                                  : 0

                                return (
                                  <tr 
                                    key={cost._id} 
                                    className="border-b border-gray-100 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors"
                                  >
                                    <td className="px-4 py-3 text-gray-900 dark:text-gray-50 font-medium">{cost.category}</td>
                                    <td className="px-4 py-3 text-right text-gray-700 dark:text-gray-300">
                                      ${cost.plannedAmount.toLocaleString()}
                                    </td>
                                    <td className="px-4 py-3 text-right">
                                      <input
                                        type="number"
                                        value={cost.actualAmount}
                                        onChange={e => updateActual(cost._id, Number(e.target.value))}
                                        className="bg-gray-50 dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded px-3 py-1.5 w-28 text-right text-gray-900 dark:text-gray-50 text-sm font-medium hover:border-gray-400 dark:hover:border-gray-500 focus:outline-none focus:border-blue-500 dark:focus:border-blue-400 transition-colors"
                                      />
                                    </td>
                                    <td className={`px-4 py-3 text-right font-semibold ${
                                      variance > 0
                                        ? "text-red-600 dark:text-red-400"
                                        : "text-emerald-600 dark:text-emerald-400"
                                    }`}>
                                      ${variance.toLocaleString()} ({variancePercent.toFixed(1)}%)
                                    </td>
                                  </tr>
                                )
                              })}
                            </tbody>
                          </table>
                        </div>

                        {/* Totals Summary */}
                        <div className="mt-6 pt-6 border-t border-gray-200 dark:border-gray-700">
                          <div className="grid grid-cols-3 gap-4">
                            <div className="bg-gray-50 dark:bg-gray-700/50 rounded-lg p-4">
                              <p className="text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">Total Planned</p>
                              <p className="text-lg font-bold text-gray-900 dark:text-gray-50">
                                ${totalPlanned.toLocaleString()}
                              </p>
                            </div>
                            <div className="bg-gray-50 dark:bg-gray-700/50 rounded-lg p-4">
                              <p className="text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">Total Actual</p>
                              <p className="text-lg font-bold text-gray-900 dark:text-gray-50">
                                ${totalActual.toLocaleString()}
                              </p>
                            </div>
                            <div className={`rounded-lg p-4 ${
                              totalVariance > 0
                                ? "bg-red-50 dark:bg-red-900/20"
                                : "bg-emerald-50 dark:bg-emerald-900/20"
                            }`}>
                              <p className={`text-xs font-medium mb-1 ${
                                totalVariance > 0
                                  ? "text-red-600 dark:text-red-400"
                                  : "text-emerald-600 dark:text-emerald-400"
                              }`}>
                                Total Variance
                              </p>
                              <p className={`text-lg font-bold ${
                                totalVariance > 0
                                  ? "text-red-700 dark:text-red-300"
                                  : "text-emerald-700 dark:text-emerald-300"
                              }`}>
                                ${totalVariance.toLocaleString()} ({variancePercent.toFixed(1)}%)
                              </p>
                            </div>
                          </div>
                        </div>
                      </>
                    ) : (
                      <div className="py-12 text-center">
                        <DollarSign className="w-12 h-12 text-gray-300 dark:text-gray-600 mx-auto mb-4" />
                        <p className="text-gray-600 dark:text-gray-400 mb-4">No cost categories added yet</p>
                        <button
                          onClick={addCost}
                          className="px-4 py-2 bg-blue-600 hover:bg-blue-700 dark:bg-blue-600 dark:hover:bg-blue-700 text-white rounded-lg font-medium text-sm transition-colors"
                        >
                          + Add First Cost Category
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              )}

              {activeTab === "snapshot" && (
                <>
                  {data.phase1 ? (
                    <div className="bg-gray-50 dark:bg-gray-900 rounded-lg p-6 overflow-auto border border-gray-200 dark:border-gray-700">
                      <pre className="text-xs text-gray-700 dark:text-gray-300 font-mono whitespace-pre-wrap break-words">
                        {JSON.stringify(data.phase1, null, 2)}
                      </pre>
                    </div>
                  ) : (
                    <div className="text-center py-12">
                      <FileText className="w-12 h-12 text-gray-300 dark:text-gray-600 mx-auto mb-4" />
                      <p className="text-gray-600 dark:text-gray-400">No phase 1 data available</p>
                    </div>
                  )}
                </>
              )}
            </div>
          </div>
        </div>
      </div>
    </AdminLayout>
  )
}